                button_Add_Anim_Images.Enabled = true;
                Directory.CreateDirectory(dirName);
                LoadImage(dirName);
                PreviewView = false;
                ShowElemetsWatchFace();
                PreviewView = true;
                groupBox_AddElemets.Enabled = true;

                PreviewImage();
                FormText();
            }
