                    break;
                case "ElementUVIndex":
                    panel = panel_UC_UVIndex;
                    break;
                case "ElementHumidity":
                    panel = panel_UC_Humidity;
                    break;
                case "ElementAltimeter":
                    panel = panel_UC_Altimeter;
                    break;
                case "ElementSunrise":
                    panel = panel_UC_Sunrise;
                    break;
                case "ElementWind":
                    panel = panel_UC_Wind;
                    break;
                case "ElementMoon":
                    panel = panel_UC_Moon;
                    break;
                case "ElementImage":
                    panel = panel_UC_Image;
                    break;
                case "ElementCompass":
                    panel = panel_UC_Compass;
                    break;

                case "ElementAlarmClock":
                    panel = panel_UC_AlarmClock;
                    break;
                case "ElementTrainingLoad":
                    panel = panel_UC_TrainingLoad;
                    break;
                case "ElementVO2Max":
                    panel = panel_UC_VO2Max;
                    break;
                case "ElementAQI":
                    panel = panel_UC_AQI;
                    break;
                case "ElementBodyTemp":
                    panel = panel_UC_BodyTemp;
                    break;
                case "ElementFloor":
                    panel = panel_UC_Floor;
                    break;
                case "ElementReadiness":
                    panel = panel_UC_Readiness;
                    break;
                case "ElementHRV":
                    panel = panel_UC_HRV;
                    break;
                case "ElementBioCharge":
                    panel = panel_UC_BioCharge;
                    break;
                case "ElementSleep":
                    panel = panel_UC_Sleep;
                    break;
                case "ElementTextWidgets":
                    panel = panel_UC_TextWidgets;
                    break;

                case "Buttons":
                    panel = panel_UC_Buttons;
                    break;
                case "SwitchBG":
                    panel = panel_UC_Switch_Background;
                    break;

                case "DisconnectAlert":
                    panel = panel_UC_DisconnectAlert;
                    break;
                case "RepeatAlert":
                    panel = panel_UC_RepeatingAlert;
                    break;
                case "TopImage":
                    panel = panel_UC_TopImage;
                    break;
                case "ElementScript":
                    panel = panel_UC_JS;
                    break;
            }
            if (panel == null) return;
            int realPos = tableLayoutPanel_ElemetsWatchFace.GetRow(panel);
            if (realPos == position) return;
            if (realPos < position)
            {
                for (int i = realPos; i < position; i++)
                {
                    Control panel2 = tableLayoutPanel_ElemetsWatchFace.GetControlFromPosition(0, i + 1);
                    if (panel2 == null) return;
                    //string n = panel2.Name;
                    tableLayoutPanel_ElemetsWatchFace.SetRow(panel2, i);
                    tableLayoutPanel_ElemetsWatchFace.SetRow(panel, i + 1);
                }
            }
            else
            {
                for (int i = realPos; i > position; i--)
                {
                    Control panel2 = tableLayoutPanel_ElemetsWatchFace.GetControlFromPosition(0, i - 1);
                    if (panel2 == null) return;
                    tableLayoutPanel_ElemetsWatchFace.SetRow(panel, i - 1);
                    tableLayoutPanel_ElemetsWatchFace.SetRow(panel2, i);
                }
            }
        }

