        private void comboBox_watch_model_SelectedIndexChanged(object sender, EventArgs e)
        {
            if (comboBox_watch_model.SelectedIndex == -1) return;
            ProgramSettings.Watch_Model = comboBox_watch_model.Text;

            Logger.WriteLine($"* comboBox_watch_model_SelectedIndexChanged : {ProgramSettings.Watch_Model}");
            SelectedModel = AvailableConfigurations[ProgramSettings.Watch_Model]; // глобальная переменная чтобы каждый раз не считывать
            Logger.WriteLine($"Loaded configuration: {SelectedModel}");
            pictureBox_Preview.Size = new Size((int)(SelectedModel.scaling.scaling_0_5.w * currentDPI), (int)(SelectedModel.scaling.scaling_0_5.h * currentDPI));
            //uCtrl_Text_SystemFont_Opt.SetScreenSize(SelectedModel.background.w, SelectedModel.background.h);

            // изменяем размер панели для предпросмотра если она не влазит
            if (pictureBox_Preview.Top + pictureBox_Preview.Height > label_watch_model.Top)
            {
                float newHeight = label_watch_model.Top - pictureBox_Preview.Top;
                float scale = newHeight / pictureBox_Preview.Height;
                pictureBox_Preview.Size = new Size((int)(pictureBox_Preview.Width * scale), (int)(pictureBox_Preview.Height * scale));
            }

            if ((formPreview != null) && (formPreview.Visible))
            {
                formPreview.radioButton_CheckedChanged(sender, e);
            }

            if (Settings_Load) return;

            if (Watch_Face == null) Watch_Face = new WATCH_FACE();
            if (Watch_Face.WatchFace_Info == null) Watch_Face.WatchFace_Info = new WatchFace_Info();

            textBox_WatchSkin_Path.Text = @"\Skin\" + SelectedModel.watchSkin; if (SelectedModel.watchSkin == null || SelectedModel.watchSkin.Length == 0)
            {
                textBox_WatchSkin_Path.Text = "";
            }

            if (Watch_Face.WatchFace_Info == null) Watch_Face.WatchFace_Info = new WatchFace_Info();
            //Watch_Face.WatchFace_Info.DeviceName = SelectedModel.int_id;  // Отказываемся от int_id
            Watch_Face.WatchFace_Info.DeviceName = ProgramSettings.Watch_Model;

            if (Watch_Face.ScreenNormal != null && Watch_Face.ScreenNormal.Background != null)
            {
                if (Watch_Face.ScreenNormal.Background.BackgroundColor != null)
                {
                    Watch_Face.ScreenNormal.Background.BackgroundColor.w = SelectedModel.background.w;
                    Watch_Face.ScreenNormal.Background.BackgroundColor.h = SelectedModel.background.h;
                }
                if (Watch_Face.ScreenNormal.Background.BackgroundImage != null)
                {
                    Watch_Face.ScreenNormal.Background.BackgroundImage.w = SelectedModel.background.w;
                    Watch_Face.ScreenNormal.Background.BackgroundImage.h = SelectedModel.background.h;
                }
            }

            if (Watch_Face.ScreenAOD != null && Watch_Face.ScreenAOD.Background != null)
            {
                if (Watch_Face.ScreenAOD.Background.BackgroundColor != null)
                {
                    Watch_Face.ScreenAOD.Background.BackgroundColor.w = SelectedModel.background.w;
                    Watch_Face.ScreenAOD.Background.BackgroundColor.h = SelectedModel.background.h;
                }
                if (Watch_Face.ScreenAOD.Background.BackgroundImage != null)
                {
                    Watch_Face.ScreenAOD.Background.BackgroundImage.w = SelectedModel.background.w;
                    Watch_Face.ScreenAOD.Background.BackgroundImage.h = SelectedModel.background.h;
                }
            }

            string JSON_String = JsonConvert.SerializeObject(ProgramSettings, Formatting.Indented, new JsonSerializerSettings
            {
                //DefaultValueHandling = DefaultValueHandling.Ignore,
                NullValueHandling = NullValueHandling.Ignore
            });
            File.WriteAllText(Application.StartupPath + @"\Settings.json", JSON_String, Encoding.UTF8);

            if (Watch_Face != null && Watch_Face.ScreenNormal != null && Watch_Face.ScreenNormal.Background != null)
                ChangSizeBackground(Watch_Face.ScreenNormal.Background);

            if (Watch_Face != null && Watch_Face.ScreenAOD != null && Watch_Face.ScreenAOD.Background != null)
                ChangSizeBackground(Watch_Face.ScreenAOD.Background);;

            uCtrl_Weather_FewDay_Elm.GraphUse = SelectedModel.versionOS >= 3;
            uCtrl_HRV_Elm.Progress_available = SelectedModel.versionOS >= 5;
            uCtrl_Wind_Elm.WindSpeed_available = SelectedModel.versionOS > 4;

            resetCaptureArea(); // сбрасываем область захвата для предпросмотра, так как размеры могли измениться

            PreviewImage();
            JSON_Modified = true;
            FormText();

            //JSON_write();
            //PreviewImage();
        }

        private void ChangSizeBackground(Background background)
        {
            //Classes.AmazfitPlatform currPlatform = AvailableConfigurations[ProgramSettings.Watch_Model];
            if (background.BackgroundColor != null)
            {
                background.BackgroundColor.w = SelectedModel.background.w;
                background.BackgroundColor.h = SelectedModel.background.h;
            }
            if (background.BackgroundImage != null)
            {
                background.BackgroundImage.w = SelectedModel.background.w;
                background.BackgroundImage.h = SelectedModel.background.h;
            }
        }

        private async void button_pack_zip_Click(object sender, EventArgs e)
        {
            // сохранение если файл не сохранен
            if (SaveRequest() == DialogResult.Cancel) return;

            if (ProjectDir == null || Watch_Face == null) return;

            string SaveFileName = Path.GetFileNameWithoutExtension(FileName);
            if (Watch_Face.WatchFace_Info.WatchFaceName != null && Watch_Face.WatchFace_Info.WatchFaceName != "")
                SaveFileName = Watch_Face.WatchFace_Info.WatchFaceName;
            string zipName = ProjectDir + @"\" + SaveFileName + ".zip";

            zipName = await CreateWatchFace(zipName);

            if (ProgramSettings.CreateZPK && File.Exists(zipName))
            {
                string zpkPath = CreateZPK(zipName);
                if (zpkPath.Length > 0 && File.Exists(zpkPath)) zipName = zpkPath;
            }

            //if (ProgramSettings.CreateZPK && File.Exists(zipName))
            //{
            //    string zabPath = CreateZAB(zipName);
            //    if (zabPath.Length > 0 && File.Exists(zabPath)) zipName = zabPath;
            //}

            // открываем файл если создали его
            if (File.Exists(zipName))
            {
                if (ProgramSettings.Settings_Pack_Dialog)
                {
                    if (MessageBox.Show(Properties.FormStrings.Message_GoToFile_Text,
                    Properties.FormStrings.Message_GoToFile_Caption,
                    MessageBoxButtons.YesNo, MessageBoxIcon.Question) == DialogResult.Yes)
                    {
                        Process.Start(new ProcessStartInfo("explorer.exe", " /select, " + zipName));
                    }
                }
                else if (ProgramSettings.Settings_Pack_GoToFile)
                {
                    Process.Start(new ProcessStartInfo("explorer.exe", " /select, " + zipName));
                } 
            }

#if !DEBUG
            string tempDir = Application.StartupPath + @"\Temp";
            if (Directory.Exists(tempDir)) DeleteDirectory(tempDir);
#endif
            progressBar1.Visible = false;
        }

