                                script.resume_call = true;
                            }
                            if (pause_call.Length > 5)
                            {
                                string user_script_fileName = Path.Combine(projectPath, "JS", "pause_call.js");
                                File.WriteAllText(user_script_fileName, pause_call, Encoding.UTF8);
                                script.pause_call = true;
                            } 
                        }

                        if (script_AOD != null && user_script_AOD.Length > 5)
                        {
                            string user_script_fileName = Path.Combine(projectPath, "JS", "AOD_user_script.js");
                            File.WriteAllText(user_script_fileName, user_script_AOD, Encoding.UTF8);
                            script_AOD.user_script = true;
                        }
                    }
                    #endregion

                    string Watch_Face_String = JsonConvert.SerializeObject(Watch_Face, Formatting.Indented, new JsonSerializerSettings
                    {
                        //DefaultValueHandling = DefaultValueHandling.Ignore,
                        NullValueHandling = NullValueHandling.Ignore
                    });
                    try
                    {
                        projectName = Regex.Replace(projectName, @"[^\w\.@-]", "-",
                                        RegexOptions.None, TimeSpan.FromSeconds(1.5));
                    }
                    catch (Exception)
                    {
                    }
                    string fullProjectName = Path.Combine(projectPath, projectName + ".json");
                    File.WriteAllText(fullProjectName, Watch_Face_String, Encoding.UTF8);

                    FileName = Path.GetFileName(fullProjectName);
                    ProjectDir = Path.GetDirectoryName(fullProjectName);
                    LoadJson(fullProjectName);
                }
                //else MessageBox.Show(Properties.FormStrings.Message_ErrorReadJS, Properties.FormStrings.Message_Error_Caption,
                //    MessageBoxButtons.OK, MessageBoxIcon.Error);

                progressBar1.Visible = false;

                //FileName = Path.GetFileName(openFileDialog.FileName);
                ProjectDir = projectPath;
            }
#if !DEBUG
            if (Directory.Exists(tempDir)) DeleteDirectory(tempDir);
#endif
        }

        private void Unpack_Zpk(string fullFileName)
        {
            if (!File.Exists(fullFileName)) return;
            string tempDir = Application.StartupPath + @"\Temp";
            if (Directory.Exists(tempDir)) DeleteDirectory(tempDir);
            Directory.CreateDirectory(tempDir);

            string projectName = Path.GetFileNameWithoutExtension(fullFileName);
            projectName = projectName.Replace(" ", "_");
            using (Ionic.Zip.ZipFile zip = Ionic.Zip.ZipFile.Read(fullFileName))
            {
                List<Ionic.Zip.ZipEntry> fileList = zip.Entries.ToList();
                if (IsWatchFace(fileList))
                {
                    Unpack_Zip(fullFileName);
                    return;
                }
                Ionic.Zip.ZipEntry item = fileList.Find(f => f.FileName == "device.zip");
                if (item != null)
                {
                    item.Extract(tempDir, Ionic.Zip.ExtractExistingFileAction.OverwriteSilently); // распаковываем
                    string fileName = Path.Combine(tempDir, "device.zip");
                    string newFileName = Path.Combine(tempDir, projectName + ".zip");
                    if (File.Exists(fileName)) File.Move(fileName, newFileName);
                    Unpack_Zip(newFileName, false);
                }
            }

        }

        // Проверяем что есть необходимые файлы для циферблата
        private bool IsWatchFace(List<Ionic.Zip.ZipEntry> fileList)
        {
            bool appJs = false;
            bool appJson = false;
            bool assets = false;
            foreach (Ionic.Zip.ZipEntry item in fileList)
            {
                if (item.FileName == "app.js") appJs = true;
                if (item.FileName == "app.bin") appJs = true;
                if (item.FileName == "app.json") appJson = true;
                if (item.FileName.StartsWith("assets/")) assets = true;
                if (appJs && appJson && assets) return true;
            }
            return false;
        }

        private bool SetModelByID (int id)
        {
            foreach (KeyValuePair<string, Classes.AmazfitPlatform> config in AvailableConfigurations)
            {
                Classes.AmazfitPlatform model = config.Value;
                if(model.deviceSource_ids != null && model.deviceSource_ids.Length > 0)
                {
                    for (int i = 0; i < model.deviceSource_ids.Length; i++)
                    {
                        if(id == model.deviceSource_ids[i])
                        {
                            ProgramSettings.Watch_Model = config.Key;
                            if (AvailableConfigurations.ContainsKey(ProgramSettings.Watch_Model))
                            {
                                comboBox_watch_model.Text = ProgramSettings.Watch_Model;
                                return true;
                            }
                        }
                    }
                }
            }
            return false;
        }

        /// <summary>Получаем список файлов в папке</summary>
        /// <param name="start_path">Начальная папка для просмотра</param>
        /// <param name="mask">Маска для поиска файлов</param>
        /// <param name="depth">Глубина просмотра подкаталогов</param>
        /// <param name="relative_path">Начальная папка? относительно которой будут возвращатся пути файлов</param>
        private List<string> GetRecursFiles(string start_path, string mask, int depth, string relative_path)
        {
            List<string> listFiles = new List<string>();
            if (depth < 0) return listFiles;
            depth--;
            try
            {
                string[] folders = Directory.GetDirectories(start_path);
                foreach (string folder in folders)
                {
                    //ls.Add("Папка: " + folder);
                    listFiles.AddRange(GetRecursFiles(folder, mask, depth, relative_path));
                }
                string[] files = Directory.GetFiles(start_path, mask);
                foreach (string fileName in files)
                {
                    if (relative_path.Length > 3) listFiles.Add(fileName.Replace(relative_path, ""));
                    else listFiles.Add(fileName);
                }
            }
            catch (System.Exception e)
            {
                MessageBox.Show(e.Message);
            }
            return listFiles;
        }

        /// <summary>Получаем список файлов в папке</summary>
        /// <param name="start_path">Начальная папка для просмотра</param>
        /// <param name="depth">Глубина просмотра подкаталогов</param>
        /// <param name="relative_path">Начальная папка? относительно которой будут возвращатся пути файлов</param>
        private List<string> GetRecursDirectories(string start_path, int depth, string relative_path)
        {
            List<string> listFiles = new List<string>();
            if (depth < 0) return listFiles;
            depth--;
            try
            {
                string[] folders = Directory.GetDirectories(start_path);
                foreach (string folder in folders)
                {
                    if (relative_path.Length > 3) listFiles.Add(folder.Replace(relative_path, ""));
                    else listFiles.Add(folder);
                    listFiles.AddRange(GetRecursDirectories(folder, depth, relative_path));
                }
            }
            catch (System.Exception e)
            {
                MessageBox.Show(e.Message);
            }
            return listFiles;
        }

        /// <summary>Рекурсивно удаляем все файлы и подпапки к каталоге</summary>
        public static void DeleteDirectory(string target_dir)
        {
            foreach (string file in Directory.GetFiles(target_dir))
            {
                File.Delete(file);
            }

            foreach (string subDir in Directory.GetDirectories(target_dir))
            {
                DeleteDirectory(subDir);
            }

            Thread.Sleep(1); // This makes the difference between whether it works or not. Sleep(0) is not enough.
            Directory.Delete(target_dir);
        }

