                    dateDay = (ElementDateDay)Watch_Face.ScreenAOD.Elements.Find(e => e.GetType().Name == "ElementDateDay");
                }
            }
            if (dateDay != null)
            {
                hmUI_widget_IMG_POINTER img_pointer = null;
