                        else HideAllElemenrOptions();
                        break;
                    case "Day_Month_Font":
                        if (uCtrl_DateDay_Elm.checkBox_Day_Month_Font.Checked)
                        {
                            text = dateDay.Day_Month_Font;
                            Read_Text_Options(text, false, true, true);
