                        break;
                    case "454 (T-Rex 2)":
                        suffix = "_T_Rex_2";
                        DeviceName = "T-Rex 2";
                        break;
                    case "454 (T-Rex Ultra)":
                        suffix = "_T_Rex_Ultra";
                        DeviceName = "T-Rex Ultra";
                        break;
                    case "466 (Active 2)":
                        suffix = "_Active_2";
                        DeviceName = "Active 2";
                        break;
                    case "466 (Active 3 Premium)":
                        suffix = "_Active_3_Premium";
                        DeviceName = "Active 3 Premium";
                        break;
                    case "466 (Cheetah 2 Pro)":
                        suffix = "_Cheetah_2_Pro";
                        DeviceName = "Cheetah 2 Pro";
                        break;
                    case "466 (GTR 4)":
                        suffix = "_GTR_4";
                        DeviceName = "GTR 4";
                        break;
                    case "466 (T-Rex 3 Pro 44mm)":
                        suffix = "_T_Rex_3_Pro_44mm";
                        DeviceName = "T-Rex 3 Pro (44mm)";
                        break;
                    case "480 (Active Max)":
                        suffix = "_Active_Max";
                        DeviceName = "Active Max";
                        break;
                    case "480 (Balance)":
                        suffix = "_Balance";
                        DeviceName = "Balance";
                        break;
                    case "480 (Balance 2)":
                        suffix = "_Balance_2";
                        DeviceName = "Balance 2";
                        break;
                    case "480 (Balance 3)":
                        suffix = "_Balance_3";
                        DeviceName = "Balance 3";
                        break;
                    case "480 (Balance Ultra)":
                        suffix = "_Balance_Ultra";
                        DeviceName = "Balance Ultra";
                        break;
                    case "480 (Cheetah Pro)":
                        suffix = "_Cheetah_Pro";
                        DeviceName = "Cheetah Pro";
                        break;
                    case "480 (Cheetah 2 Ultra)":
                        suffix = "_Cheetah_2_Ultra";
                        DeviceName = "Cheetah Ultra";
                        break;
                    case "480 (GTR 3 Pro)":
                        suffix = "_GTR_3_Pro";
                        DeviceName = "GTR 3 Pro";
                        break;
                    case "480 (T-Rex 3)":
                        suffix = "_T_Rex_3";
                        DeviceName = "T-Rex 3";
                        break;
                    case "480 (T-Rex 3 Pro 48mm)":
                        suffix = "_T_Rex_3_Pro_48mm";
                        DeviceName = "T-Rex 3 Pro (48mm)";
                        break;
                    case "480 (T-Rex Ultra 2)":
                        suffix = "_T_Rex_Ultra_2";
                        DeviceName = "T-Rex Ultra 2";
                        break;
                    default:
                        suffix = "_Custom_" + numericUpDown_ConvertingOutput_Custom.Value.ToString();
                        break;
                }

                scale = (float)(numericUpDown_ConvertingOutput_Custom.Value / numericUpDown_ConvertingInput_Custom.Value);

                string newFullDirName = ProjectDir + suffix;
                string newDirName = Path.GetFileName(newFullDirName);
                if (Directory.Exists(newFullDirName))
                {
                    DialogResult dr = MessageBox.Show(Properties.FormStrings.Message_WarningConverting_Text1
                        + newDirName + Properties.FormStrings.Message_WarningConverting_Text2,
                        Properties.FormStrings.Message_Warning_Caption, MessageBoxButtons.YesNo, MessageBoxIcon.Warning);
                    if (dr == DialogResult.Yes)
                    {
                        Directory.Delete(newFullDirName, true);
                    }
                    else return;
                }

                #region Масштабируем изображения
                Image loadedImage = null;
                Directory.CreateDirectory(newFullDirName);
                Directory.CreateDirectory(Path.Combine(newFullDirName, "assets"));

                // читаем подпапки в папках
                List<string> allDirs = GetRecursDirectories(ProjectDir + @"\assets", 5, ProjectDir + @"\assets");
                foreach (string dirNames in allDirs)
                {
                    //Console.WriteLine(dirNames);
                    if (!Directory.Exists(newFullDirName + @"\assets" + dirNames)) Directory.CreateDirectory(newFullDirName + @"\assets" + dirNames);
                }
                List<string> allImagesFiles = GetRecursFiles(ProjectDir + @"\assets", "*.png", 5, ProjectDir + @"\assets");

                foreach (string imgFileName in allImagesFiles)
                {
                    using (FileStream stream = new FileStream(ProjectDir + @"\assets" + imgFileName, FileMode.Open, FileAccess.Read))
                    {
                        loadedImage = Image.FromStream(stream);
                    }
                    string newFullFileName = newFullDirName + @"\assets" + imgFileName;
                    Bitmap bitmap = ResizeImage(loadedImage, scale);

                    bitmap.Save(newFullFileName, ImageFormat.Png);
                }
                loadedImage = null;
                #endregion

                if (Directory.Exists(ProjectDir + @"\assets\fonts"))
                {
                    CopyDirectory(ProjectDir + @"\assets\fonts", newFullDirName + @"\assets\fonts", false);
                }

                JSON_Scale(scale, DeviceName);

                string newFullFileNameJson = Path.Combine(newFullDirName,
                    Path.GetFileNameWithoutExtension(FileName) + suffix + ".json");
                string newJson = JsonConvert.SerializeObject(Watch_Face, Formatting.Indented, new JsonSerializerSettings
                {
                    //DefaultValueHandling = DefaultValueHandling.Ignore,
                    NullValueHandling = NullValueHandling.Ignore
                });
                File.WriteAllText(newFullFileNameJson, newJson, Encoding.UTF8);

                #region копирование пользовательских функций
                string scriptFileName = Path.Combine(ProjectDir, "user_functions.js");
                if (File.Exists(scriptFileName))
                {
                    string scriptFileNameNew = Path.Combine(newFullDirName, "user_functions.js");
                    File.Copy(scriptFileName, scriptFileNameNew);
                }
                scriptFileName = Path.Combine(ProjectDir, "user_script.js");
                if (File.Exists(scriptFileName))
                {
                    string scriptFileNameNew = Path.Combine(newFullDirName, "user_script.js");
                    File.Copy(scriptFileName, scriptFileNameNew);
                }
                scriptFileName = Path.Combine(ProjectDir, "user_script_start.js");
                if (File.Exists(scriptFileName))
                {
                    string scriptFileNameNew = Path.Combine(newFullDirName, "user_script_start.js");
                    File.Copy(scriptFileName, scriptFileNameNew);
                }
                scriptFileName = Path.Combine(ProjectDir, "user_script_beforeShortcuts.js");
                if (File.Exists(scriptFileName))
                {
                    string scriptFileNameNew = Path.Combine(newFullDirName, "user_script_beforeShortcuts.js");
                    File.Copy(scriptFileName, scriptFileNameNew);
                }
                scriptFileName = Path.Combine(ProjectDir, "user_script_end.js");
                if (File.Exists(scriptFileName))
                {
                    string scriptFileNameNew = Path.Combine(newFullDirName, "user_script_end.js");
                    File.Copy(scriptFileName, scriptFileNameNew);
                }
                scriptFileName = Path.Combine(ProjectDir, "resume_call.js");
                if (File.Exists(scriptFileName))
                {
                    string scriptFileNameNew = Path.Combine(newFullDirName, "resume_call.js");
                    File.Copy(scriptFileName, scriptFileNameNew);
                }
                scriptFileName = Path.Combine(ProjectDir, "pause_call.js");
                if (File.Exists(scriptFileName))
                {
                    string scriptFileNameNew = Path.Combine(newFullDirName, "pause_call.js");
                    File.Copy(scriptFileName, scriptFileNameNew);
                }

                if (Directory.Exists(ProjectDir + @"\JS"))
                {
                    CopyDirectory(ProjectDir + @"\JS", newFullDirName + @"\JS", false);
                }
                #endregion

                scriptFileName = Path.Combine(ProjectDir, "Preview.States");
                if (File.Exists(scriptFileName))
                {
                    string scriptFileNameNew = Path.Combine(newFullDirName, "Preview.States");
                    File.Copy(scriptFileName, scriptFileNameNew);
                }

                FileName = Path.GetFileName(newFullFileNameJson);
                ProjectDir = Path.GetDirectoryName(newFullFileNameJson);

                LoadJson(newFullFileNameJson);

                MessageBox.Show(Properties.FormStrings.Message_ConvertingCompleted_Text,
                        Properties.FormStrings.Message_Warning_Information, MessageBoxButtons.OK, MessageBoxIcon.Information);
            }
        }

